// Stripe webhook signature verification.
// Header format: Stripe-Signature: t=<unix>,v1=<hmac_sha256>
const crypto = require('crypto');
const headers = $input.item.json.headers || {};
const rawBody = $input.item.json.rawBody;
const sigHeader = headers['stripe-signature'] || headers['Stripe-Signature'] || '';
const secret = process.env.STRIPE_IDENTITY_WEBHOOK_SECRET || '';

let verified = false;
let bodyString = '';
if (Buffer.isBuffer(rawBody)) bodyString = rawBody.toString('utf8');
else if (typeof rawBody === 'string') bodyString = rawBody;
else bodyString = JSON.stringify($input.item.json.body || $input.item.json);

if (secret && sigHeader) {
  try {
    const parts = String(sigHeader).split(',').reduce(function (acc, p) { const kv = p.split('='); acc[kv[0]] = kv[1]; return acc; }, {});
    const t = parts.t;
    const v1 = parts.v1;
    if (t && v1) {
      const computed = crypto.createHmac('sha256', secret).update(t + '.' + bodyString).digest('hex');
      verified = (computed === v1);
    }
  } catch (e) { verified = false; }
} else if (!secret) {
  // Allow but flag — Mary should set the secret before going live.
  verified = true;
}

if (!verified) return { json: { _unauthorized: true, error: 'invalid stripe signature' } };

let payload = null;
try { payload = JSON.parse(bodyString); } catch (e) { payload = $input.item.json.body || {}; }

const eventType = payload.type || '';
const data = (payload.data && payload.data.object) || {};
const sessionId = data.id || null;
if (!sessionId) return { json: { _bad: true, error: 'no session id in event', event_type: eventType } };

return { json: {
  _ok: true,
  event_type: eventType,
  external_session_id: sessionId,
  status_from_stripe: data.status || null,
  verified_outputs: data.verified_outputs || null,
  last_error: data.last_error || null,
  metadata: data.metadata || {}
} };

const ctx = $('Verify Signature').item.json;
const rows = $input.item.json;
const row = Array.isArray(rows) ? rows[0] : rows;
if (!row || !row.id) return { json: { _not_found: true, external_session_id: ctx.external_session_id } };

const evt = ctx.event_type;
const now = new Date().toISOString();

// Identity outputs vary by Stripe Identity API version; capture safely.
const vo = ctx.verified_outputs || {};
const identity_data = (evt === 'identity.verification_session.verified' || ctx.status_from_stripe === 'verified') ? {
  first_name: vo.first_name || null,
  last_name: vo.last_name || null,
  dob: vo.dob || null,
  address: vo.address || null,
  id_number: vo.id_number || null,
  id_number_type: vo.id_number_type || null
} : null;

// Default AML risk score (50 baseline). > 75 forces manual review at compliance agent.
// Heuristics: missing required fields nudge risk up; non-Canadian address gets +20.
let amlRisk = 50;
if (identity_data) {
  if (!identity_data.dob) amlRisk += 10;
  if (!identity_data.address) amlRisk += 10;
  const country = identity_data.address && identity_data.address.country;
  if (country && country !== 'CA') amlRisk += 20;
}

let status = 'in_progress';
let patch = {};
if (evt === 'identity.verification_session.verified' || ctx.status_from_stripe === 'verified') {
  status = 'verified';
  patch = {
    status: 'verified',
    identity_data: identity_data,
    aml_risk_score: amlRisk,
    pep_screening_result: { status: 'manual_review_pending', note: 'Automated PEP screening lands in Phase 6.' },
    verified_at: now
  };
} else if (evt === 'identity.verification_session.requires_input' || ctx.status_from_stripe === 'requires_input') {
  status = 'in_progress';
  patch = { status: 'in_progress' };
} else if (evt === 'identity.verification_session.canceled' || evt === 'identity.verification_session.failed' || ctx.status_from_stripe === 'canceled' || (ctx.last_error && ctx.last_error.code)) {
  status = 'failed';
  patch = { status: 'failed', identity_data: identity_data || null };
} else {
  // Unknown event — log without mutating status.
  patch = {};
}

return { json: {
  kyc_id: row.id,
  client_id: row.client_id,
  lead_id: row.lead_id,
  status: status,
  patch: patch,
  trigger_compliance: status === 'verified',
  event_type: evt
} };
